VALUES
  (gen_random_uuid(), '2025-11-24', 1, 'CyberSense: Daily Digital Awareness Brief', 'A concise daily scan of emerging cyber activity, modernization insights, and practical awareness techniques to reinforce disciplined digital behavior across the workforce. Read the full brief inside.', 'A concise daily scan of emerging cyber activity, modernization insights, and practical awareness techniques to reinforce disciplined digital behavior across the workforce. Read the full brief inside.', 'newsletter/2025/Nov/11242025.html',
   'published', '2025-11-24 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-11-25', 2, 'Trust Exploited: The Shift to Social-Channel Phishing', 'A concise daily scan of emerging cyber activity, modernization insights, and practical awareness techniques to reinforce disciplined digital behavior across the workforce. Read the full brief inside.', 'A concise daily scan of emerging cyber activity, modernization insights, and practical awareness techniques to reinforce disciplined digital behavior across the workforce. Read the full brief inside.', 'newsletter/2025/Nov/11252025.html',
   'published', '2025-11-25 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-11-26', 3, 'Exploiting the Familiar: Everyday Attack Vectors', 'Digital operations continue to reveal a consistent pattern: routine platforms, trusted services, and familiar tools often carry the greatest risk because they blend into the background of daily work. Threat actors increasingly target these environments, counting on habit, convenience, and quick decision making to open pathways for compromise. This brief provides a structured daily scan of emerging threats, modernization insights, and practical awareness techniques to reinforce deliberate cyber discipline across the workforce.', 'Digital operations continue to reveal a consistent pattern: routine platforms, trusted services, and familiar tools often carry the greatest risk because they blend into the background of daily work. Threat actors increasingly target these environments, counting on habit, convenience, and quick decision making to open pathways for compromise. This brief provides a structured daily scan of emerging threats, modernization insights, and practical awareness techniques to reinforce deliberate cyber discipline across the workforce.', 'newsletter/2025/Nov/11262025.html',
   'published', '2025-11-26 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-11-27', 4, 'Signals in Motion', 'Digital activity continues to accelerate across platforms where routine behavior often outpaces deliberate verification. Threat actors capitalize on familiar communication patterns, trusted interfaces, and the rapid tempo of workplace interactions. This brief provides a focused snapshot of today’s cyber landscape, highlighting active threats, modernization developments, and practical techniques to reinforce disciplined digital habits across the workforce. The goal is to strengthen intuition one signal at a time through consistent, manageable awareness.', 'Digital activity continues to accelerate across platforms where routine behavior often outpaces deliberate verification. Threat actors capitalize on familiar communication patterns, trusted interfaces, and the rapid tempo of workplace interactions. This brief provides a focused snapshot of today’s cyber landscape, highlighting active threats, modernization developments, and practical techniques to reinforce disciplined digital habits across the workforce. The goal is to strengthen intuition one signal at a time through consistent, manageable awareness.', 'newsletter/2025/Nov/11272025.html',
   'published', '2025-11-27 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-11-28', 5, 'First Signals', 'Digital risk shifts throughout the day as platforms, devices, and services exchange information at a steady, uninterrupted pace. Adversaries study these interaction patterns and search for the moments when routine actions create unguarded access points. This edition traces several of the fault lines shaping today’s cyber activity, outlining current incidents, software weaknesses, and emerging technology trends. The brief reinforces thoughtful verification practices that support a more resilient workforce posture.', 'Digital risk shifts throughout the day as platforms, devices, and services exchange information at a steady, uninterrupted pace. Adversaries study these interaction patterns and search for the moments when routine actions create unguarded access points. This edition traces several of the fault lines shaping today’s cyber activity, outlining current incidents, software weaknesses, and emerging technology trends. The brief reinforces thoughtful verification practices that support a more resilient workforce posture.', 'newsletter/2025/Nov/11282025.html',
   'published', '2025-11-28 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-12-01', 6, 'Surface-to-Signal', 'Digital threats surface constantly across devices, networks, and software, often hidden behind routine actions and trusted platforms. Cyber adversaries exploit gaps where familiarity meets convenience, from mobile devices to development libraries and cloud services. This edition delivers a clear, focused snapshot of current threat activity, modernization developments, and practical defensive habits intended to sharpen situational awareness and support resilient behavior across the digital workforce.', 'Digital threats surface constantly across devices, networks, and software, often hidden behind routine actions and trusted platforms. Cyber adversaries exploit gaps where familiarity meets convenience, from mobile devices to development libraries and cloud services. This edition delivers a clear, focused snapshot of current threat activity, modernization developments, and practical defensive habits intended to sharpen situational awareness and support resilient behavior across the digital workforce.', 'newsletter/2025/Dec/12012025.html',
   'published', '2025-12-01 12:00:00+00', '{}', '{}', 0, 0),
  (gen_random_uuid(), '2025-12-02', 7, 'Active Engagement', 'Today', 'Today', 'newsletter/2025/Dec/12022025.html',
   'published', '2025-12-02 12:00:00+00', '{}', '{}', 0, 0),
